export default {
data() {
return {
title: 'Counter App',
count: 0
}
},
methods: {
increment() {
this.count++
},
decrement() {
this.count--
}
}
}

Vue 的模板语法优势：
v-if
v-for
v-bind
@click
React 的 JSX 语法
React 使用 JSX 语法，将 HTML 和 JavaScript 混合在一起：
import React, { useState } from 'react';
function Counter() {
const [count, setCount] = useState(0);
const increment = () => setCount(count + 1);
const decrement = () => setCount(count - 1);
return (

