2.2 数据绑定与状态管理
Vue 的响应式系统
Vue 采用响应式数据绑定系统，数据变化会自动触发视图更新：

export default {
data() {
return {
message: 'Hello Vue!',
user: {
name: 'John',
age: 25
}
}
},
computed: {
// 计算属性，会根据依赖自动缓存
greeting() {
return ${this.message} ${this.user.name};
}
},
watch: {
// 监听器，监听数据变化
'user.age'(newVal, oldVal) {
console.log(Age changed from ${oldVal} to ${newVal});
}
}
}

